class TestDeduplicate:
    def test_empty_input_returns_empty(self):
        assert multi_search.deduplicate([]) == []

    def test_keeps_first_occurrence_of_duplicate_url(self):
        results = [
            {
                "url": "https://a.example",
                "title": "first",
                "snippet": "",
                "engine": "ddg",
            },
            {
                "url": "https://a.example",
                "title": "second",
                "snippet": "",
                "engine": "ddg",
            },
        ]
        deduped = multi_search.deduplicate(results)
        assert len(deduped) == 1
        assert deduped[0]["title"] == "first"

    def test_preserves_order(self):
        results = [
            {"url": "https://a.example", "title": "a", "snippet": "", "engine": "ddg"},
            {"url": "https://b.example", "title": "b", "snippet": "", "engine": "ddg"},
            {"url": "https://c.example", "title": "c", "snippet": "", "engine": "ddg"},
        ]
        deduped = multi_search.deduplicate(results)
        assert [r["url"] for r in deduped] == [
            "https://a.example",
            "https://b.example",
            "https://c.example",
        ]

    def test_drops_entries_with_empty_url(self):
        results = [
            {"url": "", "title": "no url", "snippet": "", "engine": "ddg"},
            {"url": "https://a.example", "title": "ok", "snippet": "", "engine": "ddg"},
        ]
        deduped = multi_search.deduplicate(results)
        assert len(deduped) == 1
        assert deduped[0]["url"] == "https://a.example"


