class TestMain:
    def _run_main(self, argv: list[str]) -> str:
        buf = io.StringIO()
        with patch.object(sys, "argv", ["multi_search", *argv]):
            with redirect_stdout(buf):
                multi_search.main()
        return buf.getvalue()

    def test_unknown_engine_exits_nonzero(self, capsys):
        with patch.object(
            sys, "argv", ["multi_search", "--query", "x", "--engines", "bing"]
        ):
            with pytest.raises(SystemExit) as excinfo:
                multi_search.main()
        assert excinfo.value.code == 1
        err = capsys.readouterr().err
        assert "unknown engine" in err
        assert "bing" in err

    def test_missing_query_arg_errors(self):
        with patch.object(sys, "argv", ["multi_search"]):
            with pytest.raises(SystemExit) as excinfo:
                multi_search.main()
        # argparse exits with 2 on missing required args
        assert excinfo.value.code == 2

    def test_outputs_dedup_json(self):
        with patch.object(
            multi_search,
            "ENGINE_FUNCTIONS",
            {
                "ddg": lambda q, limit: [
                    {
                        "url": "https://a.example",
                        "title": "a",
                        "snippet": "",
                        "engine": "ddg",
                    },
                    {
                        "url": "https://a.example",
                        "title": "dup",
                        "snippet": "",
                        "engine": "ddg",
                    },
                ]
            },
        ):
            output = self._run_main(
                ["--query", "x", "--engines", "ddg", "--limit", "5"]
            )

        parsed = json.loads(output)
        assert len(parsed) == 1
        assert parsed[0]["url"] == "https://a.example"
        assert parsed[0]["title"] == "a"

    def test_engine_failure_warns_but_does_not_exit(self, capsys):
        def failing(_query, _limit):
            raise RuntimeError("network down")

        with patch.object(multi_search, "ENGINE_FUNCTIONS", {"ddg": failing}):
            output = self._run_main(["--query", "x"])

        assert json.loads(output) == []
        assert "ddg search failed" in capsys.readouterr().err


